  // Auto-translate restaurant names for non-base languages (not zh/en/pt)
  useAutoTranslateNames(displayedRestaurants, setTranslations);

  const serverTotalCount = paginatedResult?.total || 0;
  const totalCount = templateFilter === "starbucks" ? rankedStarbucksRestaurants.length : serverTotalCount;
  const hasMore = templateFilter === "starbucks"
    ? displayedRestaurants.length < rankedStarbucksRestaurants.length
    : (currentPage + 1) * PAGE_SIZE < serverTotalCount;
